# 输入模块

playerInput 键盘输入(后改为KeyBroadInput)playerInput.cs 键盘模拟摇杆信号 #region 左摇杆 上下左右 二维向量//二轴向转化targetDup = (Input.GetKey(keyUp) ? 1 : 0) - (Input.GetKey(keyDown) ? 1 : 0);//纵轴targetDright = (Input.GetKey(keyRight) ? 1 : 0) - (Input.GetKey(keyLeft) ? 1 : 0);//横轴if (inputEnable == false)//是否开启输入{    targetDup = 0;    targetDright = 0;}//平滑过渡Dup = Mathf.SmoothDamp(Dup, targetDup, ref DupVerlocity, 0.1f);Dright = Mathf.SmoothDamp(Dright, targetDright, ref DrightVerlocity, 0.1f);//方形映射到圆形Vector2 tempDAxis = SqareToCircle(new Vector2(Dup, Dright));float Dup2 = tempDAxis.x;float Dright2 = tempDAxis.y;//输入模长Dmag = Mathf.Sqrt((Dup2 * Dup2) + (Dright2 * Dright2));//输入方向Dvec = transform.right * Dright2 + transform.forward * Dup2;#endregion  上下左右

方形转化成圆形private Vector2 SqareToCircle(Vector2 input){    Vector2 output = Vector2.zero;    output.x = input.x * Mathf.Sqrt(1 - input.y * input.y / 2);    output.y = input.y * Mathf.Sqrt(1 - input.x * input.x / 2);    return output;}

方形与圆形转换
playerInput.cs 键盘长按与触发信号#region 奔跑 长按run = Input.GetKey(keyA);#endregion 奔跑#region 跳跃 触发bool newJump = Input.GetKey(keyB);if (newJump != lastJump &amp;&amp; newJump == true)//取按下的哪次    jump = true;else    jump = false;lastJump = newJump;#endregion 跳跃#region 攻击 触发bool newAttack = Input.GetKey(keyC);if (newAttack != lastAttack &amp;&amp; newAttack == true)//取按下的哪次    attack = true;else    attack = false;lastAttack = newAttack;#endregion 攻击

