抽象输入信号IUserInput将playerInput和joystickInput相同部分抽象为接口类IUserInput
public abstract class IUserInput : MonoBehaviour{    [Header("是否开启移动")] public bool inputEnable;    #region 输入参数    [Header("====== 移动前后左右 左摇杆 ======")]    public float Dup;//产生的横轴Horizontal 平滑输入    public float Dright;//产生的纵轴Vertical 平滑输入    public float Dmag;//输入模长    public Vector3 Dvec;//输入方向    protected float targetDup;//源输入    protected float targetDright;//源输入    protected float DupVerlocity;//由Mathf.SmoothDamp控制的值    protected float DrightVerlocity;//由Mathf.SmoothDamp控制的值    [Header("===== 视角 右摇杆=====")]    public float Jup;//产生的横轴Horizontal 平滑输入    public float Jright;//产生的纵轴Vertical 平滑输入    [Header("====== 奔跑 ======")]    //1.pressing signle 长按信号    public bool run;    [Header("====== 跳跃 ======")]    //2.trigger once single 触发信号    public bool jump;    protected bool lastJump;//上次jumo用于判断trigger                          //3.double triggle    [Header("====== 攻击 ======")]    //2.trigger once single 触发信号    public bool attack;    protected bool lastAttack;//上次jumo用于判断trigger    [Header("====== 举盾 ======")]    //2.trigger once single 触发信号    public bool defanse;    #endregion 输入参数    protected Vector2 SqareToCircle(Vector2 input)    {        Vector2 output = Vector2.zero;        output.x = input.x * Mathf.Sqrt(1 - input.y * input.y / 2);        output.y = input.y * Mathf.Sqrt(1 - input.x * input.x / 2);        return output;    }}

这样只要获取IUserInput就可以获得信号输入,在获取IUserInput时获取激活的那个输入方式即可

