using System.Collections;using UnityEngine;/// &lt;summary&gt;/// 按键类记录按键状态/// &lt;/summary&gt;public class MyButton : MonoBehaviour{    /// &lt;summary&gt;    /// 长按    /// &lt;/summary&gt;    public bool IsPressing = false;    /// &lt;summary&gt;    /// 按下    /// &lt;/summary&gt;    public bool OnPressed = false;    /// &lt;summary&gt;    /// 抬起    /// &lt;/summary&gt;    public bool OnReleased = false;    private bool curState = false;    private bool lastState = false;    public void Tick(bool input)    {        curState = input;        #region 长按        IsPressing = curState;        #endregion 长按        #region 按下与抬起        OnPressed = false;        OnReleased = false;        if (curState != lastState)        {            if (curState)            {                OnPressed = true;//按下            }            else            {                OnReleased = true;//抬起            }        }        lastState = curState;        #endregion 按下与抬起    }}

