Execise1public class Student{    public int age;    public string name;    public int number;    public bool sex;    public void Save(string fileName)    {        Debug.Log(GetPersistentURL(fileName));        if (!Directory.Exists(GetPersistentURL("Student")))        {            Directory.CreateDirectory(GetPersistentURL("Student"));        }        using (FileStream fs = new FileStream(GetPersistentURL("Student/" + fileName), FileMode.OpenOrCreate, FileAccess.Write))        {            byte[] bytes;            //age            bytes = BitConverter.GetBytes(age);            fs.Write(bytes, 0, bytes.Length);            //name            bytes = Encoding.UTF8.GetBytes(name);            byte[] length = BitConverter.GetBytes(bytes.Length);            fs.Write(length, 0, sizeof(int));            fs.Write(bytes, 0, bytes.Length);            //number            bytes = BitConverter.GetBytes(number);            fs.Write(bytes, 0, bytes.Length);            //sex            bytes = BitConverter.GetBytes(sex);            fs.Write(bytes, 0, bytes.Length);            fs.Flush();            fs.Close();        }    }    public static Student Load(string fileName)    {        string url = Application.persistentDataPath + "/Student/" + fileName;        if (File.Exists(url))        {            Student s = new Student();            using (FileStream fs = File.Open(url, FileMode.Open, FileAccess.Read))            {                byte[] bytes = new byte[fs.Length];                fs.Read(bytes, 0, bytes.Length);                fs.Close();                int index = 0;                s.age = BitConverter.ToInt32(bytes, index);                index += sizeof(int);                int length = BitConverter.ToInt32(bytes, index);                index += sizeof(int);                s.name = Encoding.UTF8.GetString(bytes, index, length);                index += length;                s.number = BitConverter.ToInt32(bytes, index);                index += sizeof(int);                s.sex = BitConverter.ToBoolean(bytes, index);                index += sizeof(bool);                return s;            }        }        Debug.LogError("不存在" + url);        return null;    }    public string GetPersistentURL(string url)    {        return Application.persistentDataPath + "/" + url;    }}public class Execise1 : MonoBehaviour{    private void Start()    {        Student s = new Student() { age = 0, name = "admin", number = 0, sex = true };        s.Save("admin.Test");        s= Student.Load("admin.Test");    }}

Action&lt;T&gt;是unity为我们包装的泛型委托
namespace System{    public delegate void Action&lt;in T&gt;(T obj);}

委托可以看成一个函数类型 传入的泛型T就是函数参数的类型

事件 就是 一个委托列表 本质也是一个委托
所以事件可以  事件+=委托


using System;using System.Collections.Generic;using Unity.VisualScripting.Dependencies.NCalc;public class EVENTNAME{    public const string PLAYER_DIE = "PLAYER_DIE";}public class EventCenter : BaseManager&lt;EventCenter&gt;{    //储存事件的字典    Dictionary&lt;string, Action&lt;object&gt;&gt; eventDic = new Dictionary&lt;string, Action&lt;object&gt;&gt;();    /// &lt;summary&gt;    /// 添加事件监听的方法    /// &lt;/summary&gt;    /// &lt;param name="name"&gt;&lt;/param&gt;    /// &lt;param name="action"&gt;&lt;/param&gt;    public void AddEventListener(string name, Action&lt;object&gt; action)    {        //如果有这个事件        //添加这个函数(委托)到事件里        //事件 就是 一个委托列表 本质也是一个委托        if (eventDic.ContainsKey(name))        {            eventDic[name] += action;        }        //没有这个事件 就把这个委托作为事件也就创建了一个事件        else        {            eventDic.Add(name, action);        }    }    /// &lt;summary&gt;    /// 移除事件监听的方法    /// &lt;/summary&gt;    /// &lt;param name="name"&gt;&lt;/param&gt;    /// &lt;param name="action"&gt;&lt;/param&gt;    public void RemoveEventListener(string name, Action&lt;object&gt; action)    {        if (eventDic.ContainsKey(name))        {            eventDic[name] -= action;        }    }    /// &lt;summary&gt;    /// 触发事件的方法    /// &lt;/summary&gt;    /// &lt;param name="name"&gt;&lt;/param&gt;    /// &lt;param name="info"&gt;&lt;/param&gt;    public void TriggerEvent(string name, object info)    {        if (eventDic.ContainsKey(name))        {            eventDic[name].Invoke(info);        }    }    /// &lt;summary&gt;    /// 当场景转换时清空所有事件    /// &lt;/summary&gt;    public void Clear()    {        eventDic.Clear();    }}

可以使得其他没有继承 mono 的类调用 Update 和 协程
需要配合MonoMgr使用
用MonoMgr得到一个唯一存在的MonoController
在MonoMgr里包装一次MonoController的协程,使得没有继承mono的类可以使用协程

public class MonoController : MonoBehaviour{    //更新事件    public Action UpdateEvent = null;    private void Update()    {        //调用帧更新事件        UpdateEvent?.Invoke();    }    //添加更新事件监听    public void AddUpdateEventListener(Action action)    {        UpdateEvent += action;    }    //移除更新事件监听    public void RemoveUpdateEventListener(Action action)    {        UpdateEvent -= action;    }    public void Clear()    {        UpdateEvent = null;    }}

public class MonoMgr : BaseManager&lt;MonoMgr&gt;{    //用MonoMgr得到一个唯一存在的MonoController    public MonoController controller;    //别的脚本在MonoManager.GetInstance() 的时侯    //就会在基础单例里 new MonoManager()     //然后调用这个构造函数    //创建MonoController的游戏对象并得到MonoController脚本    public MonoMgr()    {        GameObject obj = new GameObject(nameof(MonoController));        controller = obj.AddComponent&lt;MonoController&gt;();    }    //三个开启协程的方法    //注意用string函数名开启协程 只有 协程 和 函数 在同一个类里可行    //注意 要用  return controller.StartCoroutine 因为 只有controller是继承mono的    public Coroutine StartCoroutine(string methodName)    {        return controller.StartCoroutine(methodName);    }    public Coroutine StartCoroutine(string methodName, [DefaultValue("null")] object value)    {        return controller.StartCoroutine(methodName, value);    }    public Coroutine StartCoroutine(IEnumerator routine)    {        return controller.StartCoroutine(routine);    }}

加载资源
判断资源是否是GameObject对象是则实例化后方返回
异步加载传入回调

/// &lt;summary&gt;/// 资源加载管理器/// &lt;/summary&gt;public class ResMgr : BaseManager&lt;ResMgr&gt;{    //同步资源加载    public T load&lt;T&gt;(string name) where T : UnityEngine.Object    {        T res = Resources.Load&lt;T&gt;(name);        //判断资源是否是GameObject对象         //是则实例化后方返回        if (res is GameObject)            return GameObject.Instantiate(res);        else            return res;    }    //异步加载资源    //这里我们要约束 泛型Ｔ　为UnityEngine.Object    //因为 Resources 加载的是 UnityEngine.Object    //使用回调函数传递参数    //因为在协程函数里不能直接return回去    public void loadAsync&lt;T&gt;(string name, Action&lt;T&gt; callback) where T : UnityEngine.Object    {        MonoMgr.GetInstance().controller.StartCoroutine(LoadAsycIEnumerator&lt;T&gt;(name, callback));    }   //TODO:可以尝试用Task来不用回调函数    private IEnumerator LoadAsycIEnumerator&lt;T&gt;(string name, Action&lt;T&gt; callback) where T : UnityEngine.Object    {        ResourceRequest res = Resources.LoadAsync&lt;T&gt;(name);        //等待加载完毕        yield return res;        //加载完毕后判断资源是否是GameObject对象        //是则实例化后方返回        if (res.asset is GameObject)            callback(GameObject.Instantiate(res.asset) as T);        else            callback(res.asset as T);    }}

