在 a2v 里拿到 NORMAL 与 TANGENT因为切线空间的确定是通过（存储到模型里面的）法线和（存储到模型里面的）切线确定的 我们需要 TANGENT_SPACE_ROTATION 来转化 模型坐标与剪裁空间坐标，TANGENT_SPACE_ROTATION需要这两个参数
struct a2v{    //切线空间的确定是通过（存储到模型里面的）法线和（存储到模型里面的）切线确定的    float4 vertex: POSITION;    float3 normal: NORMAL;    float4 tangent: TANGENT; //tangent.w 是用来确定切线空间中坐标轴的方向的    float4 texcoord: TEXCOORD0; //纹理坐标};

在v2f里 储存uv 和 切线空间下的灯光方向struct v2f{    float4 sv_position: SV_POSITION;    float3 worldVertex: TEXCOORD;    float3 worldNormal: COLOR;    float4 uv: TEXCOORD1; //用xy储存MainTex的纹理坐标 zw储存NormalMap坐标    float3 lightDir: TEXCOORD2; //切线空间下的灯光方向};

在顶点着色器里为uv、lightDir赋值v2f vert(a2v v){    //.....略    f.uv.xy = v.texcoord.xy * _MainTex_ST.xy + _MainTex_ST.zw;    f.uv.zw = v.texcoord.xy * _NormalMap_ST.xy + _NormalMap_ST.zw;    TANGENT_SPACE_ROTATION; //的到rotaion    //ObjSpaceLightDir(v.vertex) 得到模型空间的灯光方向    //rotation 将模型空间转换到切线空间    f.lightDir = mul(rotation, ObjSpaceLightDir(v.vertex)); //得到切线空间下的灯光方向    return f;}

使用UnpackNormal转化模型坐标到切线空间坐标//把所有跟法线方向有关的运算部放在切线空间下//从法线贴图里面取得的法线方向是在切线空间下的fixed4 _Color;fixed4 frag(v2f i) :SV_Target{    float4 normalColor = tex2D(_NormalMap, i.uv.zw);    float3 tangentNormal = UnpackNormal(normalColor); //切线空间下的法线        tangentNormal.xy = tangentNormal.xy * _BumpScale;    tangentNormal = normalize(tangentNormal);    float3 lightDir = normalize(i.lightDir);    float3 mainTex = tex2D(_MainTex, i.uv.xy) * _Color;    fixed3 diffuse = mainTex * _DiffuseStrength * _Diffuse * _LightColor0.rgb * (0.5 * dot(            lightDir, tangentNormal) +        0.5);    fixed3 tempColor = diffuse + UNITY_LIGHTMODEL_AMBIENT.rgb * diffuse;    return fixed4(tempColor, 1);}

