3.Lua加载器void Start(){    LuaEnv env new LuaEnv();    //对应 test.1ua    //内置加载器会扫描预制的目录，查找是否存在 test,1ua /xLua 存在默认加载器，StreamingAssets 目录下可以加载文件     env.DoString("require('test')");    env.Dispose();}
4.自定义加载器public void MyLoader() {    LuaEnv env new LuaEnv();    //将我定义的加载器，加入到 xLua 的解析环境中     env.AddLoader(ProjectLoader);    env.DoString("require('test1')");    env.Dispose();} //自定义加载器//自定义加载器，会先于系统内置加载器执行，当自定加载器加载到文件后，后续的加载器则不会继续执行//当 Lua 代码执行 require() 函数时，自定义加载器会尝试获得文件的内容//参数：被加载 Lua 文件的路径public byte[]    ProjectLoader(ref string filepath) {    //filepath 来自于 Lua 的 require("文件名")    //构造路径，才能将 require 加载的文件指向到我们想放 Lua 的路径下去     string path = Application.dataPath;    path = path.Substring(0.path.Length -7)+"/DataPath/Lua/"+ filepath +".lua";    //将 Lua 文件读取为字节数组    //xLua 的解析环境，会执行我们自定义加载器返回的 Lua 代码     if(File.Exist(path)) {        return File.ReadAllBytes(path);    }    else {        return null;    }}

